var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하아아…","JPN":"はああ……","ENG":"*Sigh...*","TWN":"唉啊啊……"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"여기에 갇힌 뒤로 시간이 대체 얼마나 지난 거람?","JPN":"ここに閉じ込められて、もうどれくらい？","ENG":"How long has it been since we were locked up here?","TWN":"我被困在這裡有多久了？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"범인이 누군지도 모른다면서 우리만 이렇게 붙잡아 두는 게 말이 돼?","JPN":"犯人が誰なのかもわからないのに、私たちだけ拘束するなんて、ひどくない？","ENG":"They don't even know who did it. They can't lock us in here like this.","TWN":"你連兇手是誰都不清楚就把我關在這裡？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다들 우리가 여기에 갇혀있는지도 모르고 있을 텐데.","JPN":"みんなは私たちがここに閉じ込められてることも知らないんだろうな。","ENG":"I bet no one even knows we're stuck here.","TWN":"大家可能並不知道我們被關在這裡。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국 시니어의 살해현장에 있었으니, 보안을 위해 필요한 격리조치라고 봐야겠지.","JPN":"管理局シニアの殺人現場にいたのだから、保安のため必要な隔離措置だと考えるべきだろう。","ENG":"Since we were at the scene of an Administration Senior's murder, it was probably necessary to separate us for security reasons.","TWN":"管理局Senior被殺害時我們就在現場，應該是基於安全的理由採取了隔離措施吧。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그럼 적어도 사장님은 내보내 줘야 하는 거 아냐? 관리국에서 제일 높은 사람이 자기 부하를 해칠 이유가 어딨냐고.","JPN":"なら、少なくとも社長は出してもらわないとダメじゃない？　管理局で一番偉い人が自分の部下を殺すはずないし。","ENG":"If that's the case, shouldn't they at least let you free, Boss? Why would the head of the Administration harm people under him?","TWN":"那麼至少應該放老闆走吧？管理局最高負責人怎麼可能會殺害自己的部下。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"표면상으론 나도 암살자에게 당하지 않도록 보호를 받고 있는 것이네만.","JPN":"表面上、私も暗殺されないよう保護されているわけなのだが。","ENG":"On the surface, I'm also under protection against any assassination attempts.","TWN":"表面上看來，我也算是有受到保護以免被殺手殺害。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리자 권한을 박탈 당한 입장이니, 의심을 받는 것도 이상하지는 않지.","JPN":"管理者の権限を剥奪された立場なのだから、疑われるのも仕方ない。","ENG":"However, it wouldn't be weird for them to suspect me since I lost my authority as the Administrator.","TWN":"畢竟被剝奪了管理者權限，因此受到懷疑也就不足為奇了。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"지금 현장을 통솔하고 있는 사람이 우리 회사가 있던 곳 시니어라며?","JPN":"今現場を率いている人が、私たちの会社があったところのシニアだって言ってたでしょ？","ENG":"Isn't the person in charge of the case the Senior of where our company building was?","TWN":"聽說目前指揮現場的人是我們公司所在地區的Senior？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 사람이 사장님을 만난 적 있다거나, 개인적으로 싫어하는 건 아니겠지?","JPN":"その人が社長と知り合いだったとか、個人的に嫌われてるとかじゃないの？","ENG":"Has the person ever met you? Or have a reason to hate you?","TWN":"那個人是不是見過老闆？或者和老闆有私人恩怨吧？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니라고… 장담은 못하겠군.","JPN":"……否定はできないな。","ENG":"I can't say... that's not true.","TWN":"這個……我不確定。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"그라운드 원 시니어님께서 최고 관리자님을 호출하셨습니다.","JPN":"グラウンド・ワンのシニアが最高管理者さんをお呼びです。","ENG":"The Senior of Ground One has asked for your presence, Supreme Administrator.","TWN":"G1 Senior呼叫最高管理者。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"직접 대면해 나눌 얘기가 있으시다는군요.","JPN":"直接会って、話したいことがあるそうです。","ENG":"She would like to speak to you in person.","TWN":"說是有些話要見面聊。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리로 안내해주게.","JPN":"そちらに案内してくれたまえ。","ENG":"Lead the way.","TWN":"帶我去。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기… 나는?","JPN":"あの……私は？","ENG":"Uh... What about me?","TWN":"那……我呢？"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"다른 용의자 분은 이곳에 계속 남아 주시죠.","JPN":"他の容疑者さんは、こちらで待機してください。","ENG":"The remaining suspects are to stay here.","TWN":"其他嫌犯請留下。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"금방 돌아오지.","JPN":"すぐ戻る。","ENG":"I'll be back soon.","TWN":"我馬上回來。"},"stage":{"bg":"ROOM_04","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};